                    if (location.host == 'detail.1688.com' || location.host == 'detail.tmall.com' || location.host == 'chaoshi.detail.tmall.com' || location.host == 'detail.tmall.hk' || location.host == 'item.taobao.com') {
                        getGoodsId(true);
                    }
