//点击导出TXT按钮
$("body").delegate(".exportTextBtn", "click", function (e) {
  // 获取数据
  var data = "";
  commercialMatchList.forEach(function (item) {
    data += item.title + "，" + item.goodsId + "，" + item.link + "，" + item.price + "，" + item.imgUrl + "，" + item.shopName + "，" + item.monthSold + "，" + item.repurchaseRate + "，" + "\r\n";
  });
  // 创建TXT文件
  var blob = new Blob([data], {type: 'text/plain;charset=utf-8'});
  // 添加数据到TXT文件
  var url = URL.createObjectURL(blob);
  // 下载TXT文件
  var a = document.createElement("a");
  a.href = url;
    a.download = getTranslate('Commoditycomparison') + new Date().toLocaleDateString();
  document.body.appendChild(a);
  a.click();
  // 清理资源
  setTimeout(function () {
    URL.revokeObjectURL(url);
    document.body.removeChild(a);
  }, 150);
});
