//点击搜图按钮
$("body").delegate(".imgSearchContainer", "click", function (e) {
  if (userlogininfo == '') {
    showLoginAlert()
    return
  }
  e.stopPropagation();
  e.preventDefault();
  if (isNewVersion === false) {
    chrome.storage.local.get(["isNewVersion"], (result) => {
      if (JSON.stringify(result) != '{}') {
        isNewVersion = result.isNewVersion;
        if (result.isNewVersion === true) {
          imageTranslateBase64();
        } else {
          showUpdateChromPluginAlert();
        }
      } else {
        $.ajax({
            url: axiosLavelUrl + "plugin/version",
          type: 'post',
          dataType: 'json',
          data: {
            version: chrome.runtime.getManifest().version
          },
          success: function (res) {
            chrome.storage.local.set({'isNewVersion': res.data.prompt});
            if (res.data.prompt === true) {
              isNewVersion = true;
              imageTranslateBase64();
            } else {
              showUpdateChromPluginAlert();
            }
          }
        });
      }
    })
  } else {
    imageTranslateBase64();
  }
});
