//点击登录按钮
$("body").delegate("#loginBtn", "click", function () {
    let loginAccountNumberName = document.getElementById("loginAccountNumberName");
    let loginAccountNumberPassword = document.getElementById("loginAccountNumberPassword");
    let errorText = document.getElementById("errorText");
    if (loginAccountNumberName.value === '' || loginAccountNumberPassword.value === '') {
        errorText.innerHTML = getTranslate('theAccountOrPasswordIsNotEntered')//账号或密码未填写
        return
    }
    $.ajax({
        url: `${axiosUrl}?mod=inc&act=ordersysPc&str=login`,
        type: 'post',
        data: {
            username: loginAccountNumberName.value,
            password: loginAccountNumberPassword.value
        },
        dataType: 'json',
        success: function (res) {
            if (res.code != 1) {
                errorText.innerHTML = getTranslate('theUserNameOrPasswordIsIncorrect');//用户名或密码错误
                return
            }
            chrome.storage.local.set({'user_token': res.data.user_info.token});
            userlogininfo = res.data.user_info.token;
            userInfo = res.data.user_info;
            if (res.data.user_info.pic != '') {
                $("#userHeadPortraits").attr("src", res.data.user_info.pic);
            }
            if ($('#stayLoggedInInput').is(':checked')) {
                let obj = {
                    checked: true,
                    username: loginAccountNumberName.value,
                    password: loginAccountNumberPassword.value
                }
                loginInfo = obj;
                chrome.storage.local.set({'loginInfo': obj});
            } else {
                chrome.storage.local.remove('loginInfo', function () {

                });
            }
            $("#isLoginBtn").css("display", "none");
            $("#isLoginIcon").attr("src", 'data:image/svg+xml;base64,');
            $("#isLoginIcon").css('margin-right', '220px')
            layer.close(loginAlert);
            $("#userName").text(res.data.user_info.realname);
            $("#loginMessageBtn").text(getTranslate('LogOut'));//退出登录
            $(".userInfoContainer").css('display', 'flex');
            if ($('#favoriteListContainer').css('display') === 'flex') {
                $('#favoriteListContainer').empty();
                getUserFavoriteList();
            }
            layer.close(loginAlert);
        }
    });
});
