//点击ai优化详情的保存按钮
$("body").delegate('.editBtnList button:eq(0)', "click", function (e) {
    let data = {
        job_id: job_id,
        title_to: $('.titleOptimizationBox textarea').val(),
        image_to: [],
        sku_to: [],
        prop_to: [],
        desc_image_to: [],
        keywords: [$('.keywordsOptimizationBox textarea').val()],
        desc: $('.descOptimizationBox textarea').val(),
        five_desc: [$('.fiveDescOptimizationBox textarea').val()],
    }
    let status = false;
    $('.descImageFromListBox .imgItemBox').each(function () {
        if ($(this).find('input').is(':checked')) {
            data.desc_image_to.push($(this).find('img').attr('src'))
        }
    })
    $('.imageFromListBox .imgItemBox').each(function () {
        if ($(this).find('input').is(':checked')) {
            data.image_to.push($(this).find('img').attr('src'))
        }
    })
    $('.skuValue .skuItemBox').each(function () {
        if ($(this).find('input').val() === '') {
            status = true
        }
        let obj = {
            key: $(this).find('input').val(),
            values: []
        }
        let length = $(this).find('.valueListBox div').length;
        $(this).find('.valueListBox div').each(function (index) {
            if ($(this).find('input').val() === '') {
                status = true
            }
            obj.values.push($(this).find('input').val())
            if (index === length - 1) {
                data.sku_to.push(obj)
            }
        })
    })
    $('.property .propItemBox').each(function () {
        data.prop_to.push({
            key: $(this).attr('key'),
            value: $(this).attr('val')
        })
    })
    if (status) return aimaterialOptimizationShowMessage('SKU não preenchido completamente', 1)
    $.ajax({
        url: axiosLavelUrl + "ai/update?token=" + userlogininfo,
        type: 'post',
        dataType: 'json',
        data: data,
        success: function (res) {
            if (res.code != 0) return aimaterialOptimizationShowMessage(res.msg, 0)
            aimaterialOptimizationShowMessage(res.msg, 1)
            getAiOptimizationDetails();
        }
    })
})
