//cpf或cnpj输入框失焦事件
$("body").delegate('.rechargeBexsType', "blur", function (e) {
    e.target.value == '' ? $('.bexsTypeErrorText').css('display', 'block') : $('.bexsTypeErrorText').css('display', 'none');
})
//充值金额输入框输入事件
$("body").delegate('.rechargeAmount', "input", function (e) {
    let value = e.target.value.replace(/[^0-9.]/g, '');
    // 确保只有一个小数点
    let parts = value.split('.');
    if (parts.length > 2) {
        value = parts[0] + '.' + parts.slice(1).join('');
    }
    // 限制小数点后最多两位
    if (parts.length === 2 && parts[1].length > 2) {
        parts[1] = parts[1].substring(0, 2);
        value = parts.join('.');
    }
    // 更新输入框的值
    e.target.value = value;
    let USD = (value * (1 + 0.03)).toFixed(2);
    let BRL = (USD * exchangeRatebrl).toFixed(2);
    $('.walletDetailBox .rechargeBox .subtotalBox .flexAndCenter div:eq(0) span').text(USD)
    $('.walletDetailBox .rechargeBox .subtotalBox .flexAndCenter div:eq(1) span').text(BRL)
})
//充值金额输入框失焦事件
$("body").delegate('.rechargeAmount', "blur", function (e) {
    e.target.value == '' ? $('.amountErrorText').css('display', 'block') : $('.amountErrorText').css('display', 'none');
})
//点击提交充值按钮
$("body").delegate('.rechargeBtn', "click", function (e) {
    if (paymentMethodIndex === 0) {
        if ($('.rechargeFull').val() === '') {
            $('.fullErrorText').css('display', 'block')
            return
        }
        if ($('.rechargeName').val() === '') {
            $('.nameErrorText').css('display', 'block')
            return
        }
        if ($('.rechargeBexsType').val() === '') {
            $('.bexsTypeErrorText').css('display', 'block')
            return
        }
        if ($('.rechargeAmount').val() === '') {
            $('.amountErrorText').css('display', 'block')
            return
        }
        $('.fullErrorText').css('display', 'none');
        $('.nameErrorText').css('display', 'none');
        $('.bexsTypeErrorText').css('display', 'none');
        $('.amountErrorText').css('display', 'none');
        $.ajax({
            url: axiosAiUrl + "ai/sub/bexsChargeUrl",
            type: 'post',
            dataType: 'json',
            data: {
                full_name: `${$('.rechargeFull').val()} ${$('.rechargeName').val()}`,
                amount: $('.rechargeAmount').val(),
                bexs_type: $('#cpf_cnpj').val(),
                cpf_cnpj: $('.rechargeBexsType').val()
            },
            headers: {
                ClientToken: 'Bearer ' + aiToken,
            },
            success: function (res) {
                if (res.code != 0) return aimaterialOptimizationShowMessage(res.msg, 0)
                aimaterialOptimizationShowMessage(res.msg, 1);
                window.open(res.data.bexs_url)
                showRechargeSuccess();
            }
        });
    } else {
        if ($('.rechargeAmount').val() === '') {
            $('.amountErrorText').css('display', 'block')
            return
        }
        $('.amountErrorText').css('display', 'none');
        $.ajax({
            url: axiosAiUrl + "ai/sub/ebanxChargeUrl",
            type: 'post',
            dataType: 'json',
            data: {
                amount: $('.rechargeAmount').val()
            },
            headers: {
                ClientToken: 'Bearer ' + aiToken,
            },
            success: function (res) {
                if (res.code != 0) return aimaterialOptimizationShowMessage(res.msg, 0)
                aimaterialOptimizationShowMessage(res.msg, 1);
                window.open(res.data.ebanx_url)
                showRechargeSuccess();
            }
        });
    }
})
//点击再次充值按钮
$("body").delegate('.retopBtn', "click", function (e) {
    showAiWalletDetail();
})
//点击ai钱包出入金记录的搜索按钮
$("body").delegate('.aiDateSearch', "click", function (e) {
    if ($('#startDate').val() === '' && $('#endDate').val() === '') return
    if ($('#startDate').val() != '' && $('#endDate').val() === '') return aimaterialOptimizationShowMessage(getTranslate('pleaseSelectTheEndDate'), 0)//请选择结束日期
    if ($('#startDate').val() === '' && $('#endDate').val() != '') return aimaterialOptimizationShowMessage(getTranslate('pleaseSelectTheStartDate'), 0)//请选择开始日期
    getAiBillList();
})
//点击ai钱包出入金记录的重置按钮
$("body").delegate('.aiDateReset', "click", function (e) {
    $('#startDate').val("");
    $('#endDate').val("");
    aiBillInfo.aiBillFrom.page = 1;
    getAiBillList();
})
//点击ai钱包出入金记录的Excel导出按钮
$("body").delegate('.aiBillExportAsExcel', "click", function (e) {
    $.openAiDialogLoadForm();
    $.ajax({
        url: axiosAiUrl + "ai/sub/exportBill",
        type: 'post',
        xhrFields: {
            responseType: 'blob'
        },
        headers: {
            ClientToken: 'Bearer ' + aiToken,
        },
        success: function (res) {
            $.closeAiDialogLoadForm();
            const url = window.URL.createObjectURL(new Blob([res]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `${getTranslate('depositAndWithdrawalRecords')}.xlsx`);
            document.body.appendChild(link);
            link.click();
            link.remove();
        },
        error: function (res) {
            $.closeAiDialogLoadForm();
        }
    });
})
